import { env } from "cloudflare:workers";

export interface Todo {
  id: string;
  title: string;
  done: boolean;
  createdAt: number;
}

const KV_PREFIX = "todo:";

export async function getTodos(): Promise<Todo[]> {
  const kv = (env as unknown as { TODOS: KVNamespace }).TODOS;
  const list = await kv.list({ prefix: KV_PREFIX });
  const todos = await Promise.all(
    list.keys.map(async (key) => {
      const value = await kv.get(key.name);
      return value ? (JSON.parse(value) as Todo) : null;
    }),
  );
  const validTodos = todos.filter((t): t is Todo => t !== null);
  return validTodos.sort((a, b) => a.createdAt - b.createdAt);
}

export async function addTodo(title: string): Promise<void> {
  const kv = (env as unknown as { TODOS: KVNamespace }).TODOS;
  const id = crypto.randomUUID();
  const todo: Todo = {
    id,
    title,
    done: false,
    createdAt: Date.now(),
  };
  await kv.put(`${KV_PREFIX}${id}`, JSON.stringify(todo));
}

export async function toggleTodo(id: string): Promise<void> {
  const kv = (env as unknown as { TODOS: KVNamespace }).TODOS;
  const value = await kv.get(`${KV_PREFIX}${id}`);
  if (!value) return;
  const todo = JSON.parse(value) as Todo;
  todo.done = !todo.done;
  await kv.put(`${KV_PREFIX}${id}`, JSON.stringify(todo));
}

export async function deleteTodo(id: string): Promise<void> {
  const kv = (env as unknown as { TODOS: KVNamespace }).TODOS;
  await kv.delete(`${KV_PREFIX}${id}`);
}

"use server";

import { serverAction } from "rwsdk/worker";
import { addTodo, toggleTodo, deleteTodo } from "./kv";

export const addTodoAction = serverAction(async (formData: FormData) => {
  const title = (formData.get("title") as string | null)?.trim();
  if (!title) return;
  await addTodo(title);
});

export const toggleTodoAction = serverAction(async (formData: FormData) => {
  const id = formData.get("id") as string;
  if (!id) return;
  await toggleTodo(id);
});

export const deleteTodoAction = serverAction(async (formData: FormData) => {
  const id = formData.get("id") as string;
  if (!id) return;
  await deleteTodo(id);
});

"use client";

import { toggleTodoAction } from "./actions";

interface TodoCheckboxProps {
  id: string;
  title: string;
  done: boolean;
}

export function TodoCheckbox({ id, title, done }: TodoCheckboxProps) {
  return (
    <form action={toggleTodoAction}>
      <input type="hidden" name="id" value={id} />
      <input
        type="checkbox"
        name="done"
        aria-label={`Toggle ${title}`}
        defaultChecked={done}
        onChange={(e) => {
          const form = e.currentTarget.form;
          if (form) form.requestSubmit();
        }}
      />
    </form>
  );
}

"use client";

